SELECT A.SSVC_LINE_TYPE_CD, A.NIP_ALLOC_MST_SEQ, A.NIP_ALLOC_NEOSS_SEQ, A.SCUSTNAME , A.SOFFICENAME , A.SSUBSCNEALIAS, A.SSUBSCLGIPPORTDESCRIPTION, A.SSUBSCMSTIP , A.SCONNALIAS, -- 수용회선명 A.SLLNUM, -- 전용번호 A.SSAID, A.SIPMS_SVC_NM, A.SSVC_USE_TYPE_NM , A.SINSTALLADDRESS , A.SINSTALLROADADDRESS, A.SORDERNUM , A.SODRHOPEDT, A.SODRREGDT , A.SREPORT_OPINION, A.SSUBSCROUTERSERIALIP , A.SSUBSCLGIPPORTIP, A.SOFFICECODE , A.NIP_LINK_MST_SEQ , A.SANEALIAS -- 자국_장비명 , A.SAMSTIP -- 자국_장비IP , A.SAIFNAME -- 자국_IF명 , A.SAOFFICESCODE -- 자국_수용국 , A.SAOFFICESCODE_NM , A.SZNEALIAS -- 대국_장비명 , A.SZMSTIP -- 대국_장비IP , A.SZIFNAME -- 대국_IF명 , A.SZOFFICESCODE -- 대국_수용국 , A.SZOFFICESCODE_NM FROM ( SELECT A.SSVC_LINE_TYPE_CD, A.NIP_ALLOC_MST_SEQ, A.NIP_ALLOC_NEOSS_SEQ, A.SCUSTNAME , C.SLVL_NM AS SOFFICENAME , A.SSUBSCNEALIAS, A.SSUBSCLGIPPORTDESCRIPTION, A.SSUBSCMSTIP , E.SCONNALIAS, -- 수용회선명 E.SLLNUM, -- 전용번호 A.SSAID, B.SIPMS_SVC_NM, D.SSVC_USE_TYPE_NM , A.SINSTALLADDRESS , A.SINSTALLROADADDRESS, A.SORDERNUM , A.SODRHOPEDT, A.SODRREGDT , A.SREPORT_OPINION, A.SSUBSCROUTERSERIALIP , A.SSUBSCLGIPPORTIP, A.SOFFICECODE , E.NIP_LINK_MST_SEQ , E.SANEALIAS -- 자국_장비명 , E.SAMSTIP -- 자국_장비IP , E.SAIFNAME -- 자국_IF명 , E.SAOFFICESCODE -- 자국_수용국 , F.SLVL_NM AS SAOFFICESCODE_NM , E.SZNEALIAS -- 대국_장비명 , E.SZMSTIP -- 대국_장비IP , E.SZIFNAME -- 대국_IF명 , E.SZOFFICESCODE -- 대국_수용국 , G.SLVL_NM AS SZOFFICESCODE_NM FROM MST.TB_IP_ALLOC_MST A , MST.TB_IPMS_SVC_MST B , MST.TB_LVL_CD C , MST.TB_SVC_USE_TYPE_CD D, MST.TB_IP_LINK_MST E, MST.TB_LVL_CD F, MST.TB_LVL_CD G WHERE 1 = 1
AND A.NIP_ALLOC_MST_SEQ = #{nipAllocMstSeq, jdbcType=BIGINT}
AND A.NIPMS_SVC_SEQ = B.NIPMS_SVC_SEQ(+) AND A.SOFFICECODE = C.SLVL_CD(+) AND A.SSVC_USE_TYPE_CD = D.SSVC_USE_TYPE_CD(+) AND A.NIP_LINK_MST_SEQ = E.NIP_LINK_MST_SEQ(+) AND E.SAOFFICESCODE = F.SLVL_CD(+) AND E.SZOFFICESCODE = G.SLVL_CD(+) ORDER BY A.DMODIFY_DT DESC ) A WHERE 1 = 1 AND ROWNUM = 1

