SELECT ROW_NUMBER() OVER () AS INDEX,
, A.SSVC_LINE_TYPE_NM , A.SSVC_GROUP_CD , A.SSVC_GROUP_NM , A.SSVC_OBJ_CD , A.SSVC_OBJ_NM , A.SIP_VERSION_TYPE_NM , A.SIP_CREATE_TYPE_NM , A.SASSIGN_TYPE_NM , A.SASSIGN_LEVEL_NM , A.SLLNUM , A.SSUBSCNEALIAS , A.SSUBSCLGIPPORTDESCRIPTION , A.SNEOSS_DD_YN , A.RNUM , CASE WHEN A.NCNT > 3 THEN SQLJ.GETNTOA(TEXT(DECODE(FAMILY(INET(A.PIP_PREFIX)), 4, 'IPV4', 6, 'IPV6', 'IPV4'))||'|'||TO_CHAR(A.NFIRST_ADDR + 1)) ELSE A.SFIRST_ADDR END AS SFIRST_ADDR_GWIP , CASE WHEN A.NCNT > 3 THEN SQLJ.GETNTOA(TEXT(DECODE(FAMILY(INET(A.PIP_PREFIX)), 4, 'IPV4', 6, 'IPV6', 'IPV4'))||'|'||TO_CHAR(A.NLAST_ADDR - 1)) ELSE A.SLAST_ADDR END AS SLAST_ADDR_GWIP , A.NIP_LINK_MST_SEQ , A.NSUMMARY_CNT , A.SNULL0_YN , A.SINTGRM_YN FROM ( SELECT , A.SSVC_LINE_TYPE_NM , A.SSVC_GROUP_CD , A.SSVC_GROUP_NM , A.SSVC_OBJ_CD , A.SSVC_OBJ_NM , A.SIP_VERSION_TYPE_NM , A.SIP_CREATE_TYPE_NM , A.SASSIGN_TYPE_NM , A.SASSIGN_LEVEL_NM , A.SLLNUM , A.SSUBSCNEALIAS , A.SSUBSCLGIPPORTDESCRIPTION , A.SNEOSS_DD_YN , A.NIP_LINK_MST_SEQ , ROWNUM RNUM , A.NSUMMARY_CNT , A.SNULL0_YN , A.SINTGRM_YN FROM ( SELECT
, J.NIP_LINK_MST_SEQ , NVL(A.NSUMMARY_CNT, '') AS NSUMMARY_CNT , NVL(A.SNULL0_YN, '') AS SNULL0_YN , NVL(A.SINTGRM_YN, '') AS SINTGRM_YN FROM MST.TB_IP_ASSIGN_MST A
AND A.GROUP_ID = #{groupId, javaType=Object, jdbcType=OTHER, typeHandler=com.kt.ipms.legacy.cmn.typehandler.CIDRTypeHandler}
AND A.NLVL_MST_SEQ IN
#{item.nlvlSeq}
AND A.SASSIGN_LEVEL_CD IN ('IA0004','IA0005','IA0006')
AND ((A.SIP_VERSION_TYPE_CD = 'CV0001' AND A.NBITMASK >= 16) OR (A.SIP_VERSION_TYPE_CD = 'CV0002' AND A.NBITMASK >= 48)) AND A.SIP_CREATE_TYPE_CD BETWEEN 'CT0001' AND 'CT0003' AND A.SSVC_LINE_TYPE_CD BETWEEN 'CL0001' AND 'CL0002'
AND A.NLVL_MST_SEQ IN (SELECT DISTINCT NLVL_MST_SEQ FROM MST.TB_LVL_MST LM INNER JOIN MST.TB_LVL_SUB_CD LS ON LM.SSVC_LINE_TYPE_CD = LS.SSVC_LINE_TYPE_CD AND LM.SSVC_OBJ_CD = LS.SLVL_CD INNER JOIN MST.TB_IPMS_SVC_SUB SS ON LM.SSVC_LINE_TYPE_CD = SS.SSVC_LINE_TYPE_CD INNER JOIN MST.TB_IPMS_SVC_MST SM ON SM.NIPMS_SVC_SEQ = SS.NIPMS_SVC_MST_SEQ WHERE SLOFFICECODE = #{sicisofficescode, jdbcType=VARCHAR} )
AND NVL(A.SNULL0_YN, '') = #{snull0Yn, jdbcType=VARCHAR}
AND NVL(A.SINTGRM_YN, '') = #{sintgrmYn, jdbcType=VARCHAR}
AND (
NVL(A.NSUMMARY_CNT, 0) >= #{summaryCnt, jdbcType=INTEGER}
1=0
1=1
