GROUP BY A.SOFFICECODE , B.SLVL_NM , A.SSUBSCNEALIAS , A.SMODELNAME , A.SSUBSCMSTIP )

SELECT A.SRSSOFFICESCODE AS SOFFICECODE , DECODE(B.SLVL_NM ,NULL ,'',B.SLVL_NM) as SOFFICENAME , A.SIP_HOST_NM AS SSUBSCNEALIAS , A.SMODELNAME AS SMODELNAME , A.SIP_BLOCK AS SSUBSCMSTIP , A.SNESCODE AS SSUBSCNESCODE FROM MST.TB_IP_HOST_MST A , MST.TB_LVL_CD B , MST.TB_IP_HOST_TYPE_CD C WHERE 1=1 AND A.SRSSOFFICESCODE = B.SLVL_CD(+) AND A.SIP_HOST_TYPE_CD = C.SIP_HOST_TYPE_CD
