SELECT A.NIP_ASSIGN_MST_SEQ , A.PIP_PREFIX , A.SFIRST_ADDR , A.SLAST_ADDR , A.NBITMASK , A.SIP_CREATE_TYPE_NM , A.SSVC_LINE_TYPE_NM , A.SASSIGN_LEVEL_NM , A.VALIDATIONCHECK , A.SIP_ASSIGN_SUB_NM , A.SSVC_GROUP_NM , A.SSVC_OBJ_NM , A.SICISOFFICESNAME , A.SSUBSCNEALIAS , A.SMODELNAME , A.SSUBSCLGIPPORTDESCRIPTION , A.SCONNALIAS , A.SSVC_MGROUP_NM , A.SSVC_LGROUP_NM , A.SSVC_USE_TYPE_NM , A.SASSIGN_TYPE_NM , A.SLLNUM , A.SSAID , A.SCUSTNAME , A.RNUM , A.NIP_ALLOC_MST_SEQ FROM ( SELECT A.NIP_ASSIGN_MST_SEQ , A.PIP_PREFIX , A.SFIRST_ADDR , A.SLAST_ADDR , A.NBITMASK , A.SIP_CREATE_TYPE_NM , A.SSVC_LINE_TYPE_NM , A.SASSIGN_LEVEL_NM , A.VALIDATIONCHECK , A.SIP_ASSIGN_SUB_NM , A.SSVC_GROUP_NM , A.SSVC_OBJ_NM , A.SICISOFFICESNAME , A.SSUBSCNEALIAS , A.SMODELNAME , A.SSUBSCLGIPPORTDESCRIPTION , A.SCONNALIAS , A.SSVC_MGROUP_NM , A.SSVC_LGROUP_NM , A.SSVC_USE_TYPE_NM , A.SASSIGN_TYPE_NM , A.SLLNUM , A.SSAID , A.SCUSTNAME , NVL(A.NIP_ALLOC_MST_SEQ, 0) AS NIP_ALLOC_MST_SEQ , ROWNUM RNUM FROM ( SELECT A.NIP_ASSIGN_MST_SEQ , A.PIP_PREFIX , A.SFIRST_ADDR , A.SLAST_ADDR , A.NBITMASK , G.SIP_CREATE_TYPE_NM AS SIP_CREATE_TYPE_NM , B.SSVC_LINE_TYPE_NM AS SSVC_LINE_TYPE_NM , I.SASSIGN_LEVEL_NM AS SASSIGN_LEVEL_NM , CASE WHEN A.NPRIORITY = 9 THEN 'DHCP 감사대상'::VARCHAR(10) WHEN A.NPRIORITY = 10 THEN 'CONFIG 감사대상'::VARCHAR(10) ELSE '정상'::VARCHAR(10) END AS VALIDATIONCHECK ,'' AS SIP_ASSIGN_SUB_NM , D.SLVL_NM AS SSVC_GROUP_NM , E.SLVL_NM AS SSVC_OBJ_NM , K.SLVL_NM AS SICISOFFICESNAME , MAX(SSUBSCNEALIAS) AS SSUBSCNEALIAS , MAX(SMODELNAME) AS SMODELNAME , MAX(SSUBSCLGIPPORTDESCRIPTION) AS SSUBSCLGIPPORTDESCRIPTION , MAX(SCONNALIAS) AS SCONNALIAS , L.SSVC_MGROUP_NM , M.SSVC_LGROUP_NM , N.SSVC_USE_TYPE_NM , H.SASSIGN_TYPE_NM AS SASSIGN_TYPE_NM , MAX(SLLNUM) AS SLLNUM , MAX(SSAID) AS SSAID , MAX(SCUSTNAME) AS SCUSTNAME , J.NIP_ALLOC_MST_SEQ FROM MST.TB_IP_ASSIGN_MST A , MST.TB_SVC_LINE_TYPE_CD B , MST.TB_LVL_MST C , MST.TB_LVL_CD D , MST.TB_LVL_CD E , MST.TB_IP_VERSION_TYPE_CD F , MST.TB_IP_CREATE_TYPE_CD G , MST.TB_ASSIGN_TYPE_CD H , MST.TB_ASSIGN_LEVEL_CD I , MST.TB_IP_ALLOC_MST J , MST.TB_LVL_CD K , MST.TB_SVC_MGROUP_CD L , MST.TB_SVC_LGROUP_CD M , MST.TB_SVC_USE_TYPE_CD N WHERE 1=1
AND ( ( (A.nfirst_addr >= (SELECT(BIF.UF_Search_IP_to_NUMBER(#{sfirstAddr, jdbcType=VARCHAR}, 'Y')) AS MM FROM DUAL) AND A.nlast_addr <= (SELECT(BIF.UF_Search_IP_to_NUMBER(#{sfirstAddr, jdbcType=VARCHAR}, 'N')) AS MM FROM DUAL)) ) OR ( (A.nfirst_addr <= (SELECT(BIF.UF_Search_IP_to_NUMBER(#{sfirstAddr, jdbcType=VARCHAR}, 'Y')) AS MM FROM DUAL) AND A.nlast_addr >= (SELECT(BIF.UF_Search_IP_to_NUMBER(#{sfirstAddr, jdbcType=VARCHAR}, 'N')) AS MM FROM DUAL)) ) )
AND A.SIP_VERSION_TYPE_CD = #{sipVersionTypeCd, jdbcType=CHAR}
AND (
J.SLLNUM ILIKE '%' || #{sllnum, jdbcType=VARCHAR} || '%'
)
AND (
