WHERE SASSIGN_TYPE_CD = #{sassignTypeCd, jdbcType=CHAR}
AND SEX_SVC_CD = #{sexSvcCd, jdbcType=CHAR}
AND SSVC_USE_TYPE_CD = #{ssvcUseTypeCd, jdbcType=CHAR}

SELECT A.CODE , A.NAME FROM ( SELECT A.SAOFFICESCODE AS CODE , C.SLVL_NM AS NAME FROM MST.TB_IP_LINK_MST A , MST.TB_LVL_CD C WHERE 1=1 AND A.SAOFFICESCODE = C.SLVL_CD
AND A.SAOFFICESCODE IN ( SELECT DISTINCT M.SSVC_OFFICE_CD FROM MST.TB_LVL_ROLE_SUB M INNER JOIN MST.TB_LVL_MST T ON M.SSVC_LINE_TYPE_CD = T.SSVC_LINE_TYPE_CD AND M.SSVC_OBJ_CD = T.SSVC_OBJ_CD WHERE 1=1 AND NLVL_MST_SEQ IN
#{item.nlvlSeq}
)
GROUP BY A.SAOFFICESCODE, C.SLVL_NM UNION SELECT A.SZOFFICESCODE AS CODE , C.SLVL_NM AS NAME FROM MST.TB_IP_LINK_MST A , MST.TB_LVL_CD C WHERE 1=1 AND A.SZOFFICESCODE = C.SLVL_CD
AND A.SZOFFICESCODE IN ( SELECT DISTINCT M.SSVC_OFFICE_CD FROM MST.TB_LVL_ROLE_SUB M INNER JOIN MST.TB_LVL_MST T ON M.SSVC_LINE_TYPE_CD = T.SSVC_LINE_TYPE_CD AND M.SSVC_OBJ_CD = T.SSVC_OBJ_CD WHERE 1=1 AND NLVL_MST_SEQ IN
#{item.nlvlSeq}
)
GROUP BY A.SZOFFICESCODE, C.SLVL_NM ) A ORDER BY A.NAME

SELECT A.NIP_LINK_MST_SEQ , A.PIF_SERIAL_IP -- 인터페이스 시리얼 IP , A.SANEALIAS -- 자국_장비명 , A.SAMSTIP -- 자국_장비IP , A.SAIFNAME -- 자국_IF명 , A.SALOCATIONCODE -- 자국_시설코드 , A.SAOFFICESCODE -- 자국_수용국 , B.SLVL_NM AS SAOFFICESCODE_NM , A.SZNEALIAS -- 대국_장비명 , A.SZMSTIP -- 대국_장비IP , A.SZIFNAME -- 대국_IF명 , A.SZLOCATIONCODE -- 대국_시설코드 , A.SZOFFICESCODE -- 대국_수용국 , C.SLVL_NM AS SZOFFICESCODE_NM , A.SCONNALIAS -- 수용회선명 , A.SSAID -- SAID , A.SLLNUM -- LLNUM FROM MST.TB_IP_LINK_MST A , MST.TB_LVL_CD B -- 자국 수용국 , MST.TB_LVL_CD C -- 대국 수용국 WHERE 1=1 AND B.SLVL_CD(+) = A.SAOFFICESCODE AND C.SLVL_CD(+) = A.SZOFFICESCODE
AND ( A.SAOFFICESCODE IN ( SELECT DISTINCT M.SSVC_OFFICE_CD FROM MST.TB_LVL_ROLE_SUB M INNER JOIN MST.TB_LVL_MST T ON M.SSVC_LINE_TYPE_CD = T.SSVC_LINE_TYPE_CD AND M.SSVC_OBJ_CD = T.SSVC_OBJ_CD WHERE 1=1 AND NLVL_MST_SEQ IN
#{item.nlvlSeq}
) OR A.SZOFFICESCODE IN ( SELECT DISTINCT M.SSVC_OFFICE_CD FROM MST.TB_LVL_ROLE_SUB M INNER JOIN MST.TB_LVL_MST T ON M.SSVC_LINE_TYPE_CD = T.SSVC_LINE_TYPE_CD AND M.SSVC_OBJ_CD = T.SSVC_OBJ_CD WHERE 1=1 AND NLVL_MST_SEQ IN
#{item.nlvlSeq}
) )
AND (A.SAOFFICESCODE = #{sofficescodeSrch, jdbcType=VARCHAR} OR A.SZOFFICESCODE = #{sofficescodeSrch, jdbcType=VARCHAR})
AND (A.SANEALIAS ILIKE '%' || #{snealiasSrch, jdbcType=VARCHAR} || '%' OR A.SZNEALIAS ILIKE '%' || #{snealiasSrch, jdbcType=VARCHAR} || '%')
AND (A.SAMSTIP ILIKE '%' || #{smstipSrch, jdbcType=VARCHAR} || '%' OR A.SZMSTIP ILIKE '%' || #{smstipSrch, jdbcType=VARCHAR} || '%')
AND (A.SAIFNAME ILIKE '%' || #{sifipSrch, jdbcType=VARCHAR} || '%' OR A.SZIFNAME ILIKE '%' || #{sifipSrch, jdbcType=VARCHAR} || '%')
AND CAST(A.PIF_SERIAL_IP AS TEXT) ILIKE '%' || #{pifSerialIpSrch, jdbcType=VARCHAR} || '%'
AND CAST(A.PIF_SERIAL_IP AS TEXT) = #{pifSerialIp, jdbcType=VARCHAR}
AND A.SLLNUM = #{sllnumSrch, jdbcType=VARCHAR}
GROUP BY A.NIP_LINK_MST_SEQ , A.PIF_SERIAL_IP -- 인터페이스 시리얼 IP , A.SANEALIAS -- 자국_장비명 , A.SAMSTIP -- 자국_장비IP , A.SAIFNAME -- 자국_IF명 , A.SALOCATIONCODE -- 자국_시설코드 , A.SAOFFICESCODE -- 자국_수용국 , B.SLVL_NM , A.SZNEALIAS -- 대국_장비명 , A.SZMSTIP -- 대국_장비IP , A.SZIFNAME -- 대국_IF명 , A.SZLOCATIONCODE -- 대국_시설코드 , A.SZOFFICESCODE -- 대국_수용국 , C.SLVL_NM , A.SCONNALIAS -- 수용회선명 , A.SSAID -- SAID , A.SLLNUM -- LLNUM

SELECT count(1) totalCount FROM ( SELECT A.PIF_SERIAL_IP -- 인터페이스 시리얼 IP , A.SANEALIAS -- 자국_장비명 , A.SAMSTIP -- 자국_장비IP , A.SAIFNAME -- 자국_IF명 , A.SALOCATIONCODE -- 자국_시설코드 , A.SAOFFICESCODE -- 자국_수용국 , B.SLVL_NM AS SAOFFICESCODE_NM , A.SZNEALIAS -- 대국_장비명 , A.SZMSTIP -- 대국_장비IP , A.SZIFNAME -- 대국_IF명 , A.SZLOCATIONCODE -- 대국_시설코드 , A.SZOFFICESCODE -- 대국_수용국 , C.SLVL_NM AS SZOFFICESCODE_NM , A.SCONNALIAS -- 수용회선명 , A.SSAID -- SAID , A.SLLNUM -- LLNUM FROM MST.TB_IP_LINK_MST A , MST.TB_LVL_CD B -- 자국 수용국 , MST.TB_LVL_CD C -- 대국 수용국 WHERE 1=1 AND B.SLVL_CD(+) = A.SAOFFICESCODE AND C.SLVL_CD(+) = A.SZOFFICESCODE
AND ( A.SAOFFICESCODE IN ( SELECT DISTINCT M.SSVC_OFFICE_CD FROM MST.TB_LVL_ROLE_SUB M INNER JOIN MST.TB_LVL_MST T ON M.SSVC_LINE_TYPE_CD = T.SSVC_LINE_TYPE_CD AND M.SSVC_OBJ_CD = T.SSVC_OBJ_CD WHERE 1=1 AND NLVL_MST_SEQ IN
#{item.nlvlSeq}
) OR A.SZOFFICESCODE IN ( SELECT DISTINCT M.SSVC_OFFICE_CD FROM MST.TB_LVL_ROLE_SUB M INNER JOIN MST.TB_LVL_MST T ON M.SSVC_LINE_TYPE_CD = T.SSVC_LINE_TYPE_CD AND M.SSVC_OBJ_CD = T.SSVC_OBJ_CD WHERE 1=1 AND NLVL_MST_SEQ IN
#{item.nlvlSeq}
) )
AND (A.SAOFFICESCODE = #{sofficescodeSrch, jdbcType=VARCHAR} OR A.SZOFFICESCODE = #{sofficescodeSrch, jdbcType=VARCHAR})
AND (A.SANEALIAS ILIKE '%' || #{snealiasSrch, jdbcType=VARCHAR} || '%' OR A.SZNEALIAS ILIKE '%' || #{snealiasSrch, jdbcType=VARCHAR} || '%')
AND (A.SAMSTIP ILIKE '%' || #{smstipSrch, jdbcType=VARCHAR} || '%' OR A.SZMSTIP ILIKE '%' || #{smstipSrch, jdbcType=VARCHAR} || '%')
AND (A.SAIFNAME ILIKE '%' || #{sifipSrch, jdbcType=VARCHAR} || '%' OR A.SZIFNAME ILIKE '%' || #{sifipSrch, jdbcType=VARCHAR} || '%')
AND CAST(A.PIF_SERIAL_IP AS TEXT) ILIKE '%' || #{pifSerialIpSrch, jdbcType=VARCHAR} || '%'
